kernel_src="""
#include "kernel_operator.h"
#include <cfloat>

constexpr int32_t BUFFER_NUM = 2;
constexpr float INF_NEG = -FLT_MAX;

class KernelSoftmaxCustom {
public:
    __aicore__ inline KernelSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t rowLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        rowLen_ = rowLength;
        numRows_ = (rowLen_ > 0) ? (totalLen_ / rowLen_) : 1;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(sclQueue_, 1, sizeof(float));  // scalar broadcast helper
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        if (blockNum == 0) return;

        uint32_t rowsPerBlock = CeilDiv(numRows_, blockNum);
        uint32_t startRow = blockIdx * rowsPerBlock;
        uint32_t endRow = startRow + rowsPerBlock;
        if (endRow > numRows_) endRow = numRows_;
        if (startRow >= endRow) return;

        for (uint32_t r = startRow; r < endRow; ++r) {
            processRow(r * rowLen_);
        }
    }

private:
    __aicore__ inline void processRow(uint32_t rowBase)
    {
        // Pass 1: compute max over the row
        float maxVal = INF_NEG;
        for (uint32_t col = 0; col < rowLen_; col += tileLen_) {
            uint32_t curLen = (col + tileLen_ <= rowLen_) ? tileLen_ : (rowLen_ - col);
            if (curLen == 0) break;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[rowBase + col], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();
            AscendC::ReduceMax(tmpLocal, xLocal, 0, curLen);  // axis=0
            float tileMax = tmpLocal.GetValue(0);
            tmpQueue_.FreeTensor(tmpLocal);
            if (tileMax > maxVal) maxVal = tileMax;

            inQueueX_.FreeTensor(xLocal);
        }

        // Pass 2: compute sum of exp(x - maxVal) over the row
        float sumVal = 0.0f;
        for (uint32_t col = 0; col < rowLen_; col += tileLen_) {
            uint32_t curLen = (col + tileLen_ <= rowLen_) ? tileLen_ : (rowLen_ - col);
            if (curLen == 0) break;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[rowBase + col], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();
            // t = x - maxVal, need maxTensor (broadcast maxVal to curLen)
            AscendC::LocalTensor<float> maxTensor = tmpQueue_.AllocTensor<float>();  // reuse tmpQueue? careful: two allocs at once? we'll allocate from sclQueue instead
            // Use sclQueue to hold the scalar and broadcast it
            AscendC::LocalTensor<float> sclTensor = sclQueue_.AllocTensor<float>();
            sclTensor.SetValue(0, maxVal);
            AscendC::Broadcast(maxTensor, sclTensor, curLen);
            sclQueue_.FreeTensor(sclTensor);

            AscendC::Sub(tmpLocal, xLocal, maxTensor, curLen);
            AscendC::Exp(tmpLocal, tmpLocal, curLen);

            // Reduce sum
            AscendC::LocalTensor<float> sumLocal = outQueueY_.AllocTensor<float>();
            AscendC::ReduceSum(sumLocal, tmpLocal, 0, curLen);
            sumVal += sumLocal.GetValue(0);
            outQueueY_.FreeTensor(sumLocal);

            tmpQueue_.FreeTensor(tmpLocal);
            tmpQueue_.FreeTensor(maxTensor);
            inQueueX_.FreeTensor(xLocal);
        }

        // Pass 3: compute output = exp(x - maxVal) / sumVal
        float invSum = 1.0f / sumVal;
        for (uint32_t col = 0; col < rowLen_; col += tileLen_) {
            uint32_t curLen = (col + tileLen_ <= rowLen_) ? tileLen_ : (rowLen_ - col);
            if (curLen == 0) break;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[rowBase + col], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

            // t = x - maxVal
            AscendC::LocalTensor<float> maxTensor = tmpQueue_.AllocTensor<float>();
            AscendC::LocalTensor<float> sclTensor = sclQueue_.AllocTensor<float>();
            sclTensor.SetValue(0, maxVal);
            AscendC::Broadcast(maxTensor, sclTensor, curLen);
            sclQueue_.FreeTensor(sclTensor);

            AscendC::Sub(tmpLocal, xLocal, maxTensor, curLen);
            AscendC::Exp(tmpLocal, tmpLocal, curLen);
            // multiply by invSum (scalar)
            AscendC::Muls(yLocal, tmpLocal, invSum, curLen);
            // copy out to global
            AscendC::DataCopy(yGm_[rowBase + col], yLocal, curLen);

            outQueueY_.FreeTensor(yLocal);
            tmpQueue_.FreeTensor(tmpLocal);
            tmpQueue_.FreeTensor(maxTensor);
            inQueueX_.FreeTensor(xLocal);
        }
    }

    __aicore__ inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
        return (a + b - 1u) / b;
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> sclQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t numRows_ {0};
};

extern "C" __global__ __aicore__ void softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength, tiling_data.rowLength);
    op.Process();
}
